import{_ as o,c as i,o as a,ag as l}from"./chunks/framework.DVUBUV_u.js";const p=JSON.parse('{"title":"Release history","description":"","frontmatter":{"title":"Release history"},"headers":[],"relativePath":"releases/history.md","filePath":"releases/history.md"}'),t={name:"releases/history.md"};function r(d,e,c,n,s,h){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="release-history" tabindex="-1">Release history <a class="header-anchor" href="#release-history" aria-label="Permalink to &quot;Release history&quot;">​</a></h1><h2 id="_2-0-0-2026-01-23" tabindex="-1">[2.0.0] - 2026-01-23 <a class="header-anchor" href="#_2-0-0-2026-01-23" aria-label="Permalink to &quot;[2.0.0] - 2026-01-23&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Corporate-friendly build that does not require installation.</li><li>Version tracking and notifications for new updates.</li><li>Project moved to an <code>iframe</code> entry; <code>popup</code> is no longer the primary entry point.</li></ul><hr><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Fixed a memory spike on static sites, including Docusaurus and Hugo.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Refreshed styles and overall visual design.</li></ul><h2 id="_2-1-0-2026-02-02" tabindex="-1">[2.1.0] - 2026-02-02 <a class="header-anchor" href="#_2-1-0-2026-02-02" aria-label="Permalink to &quot;[2.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="core-1" tabindex="-1">Core <a class="header-anchor" href="#core-1" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>New <code>Network</code> management tab.</li><li>Redesign for <code>iframe</code> layout instead of <code>popup</code> — more useful space on screen.</li><li>JSON layout tweaks — editor uses full app height.</li><li>Fixed tabs sticking when opening early — <code>Props</code> and <code>Pinia</code> no longer require a full page reload to appear.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Fixed favorites not resolving after reload or repeated flows.</li><li>Optimized Props for long sessions without excessive CPU; internal refactor.</li><li>Props tab overhaul — better behavior with large trees and hover search.</li><li>Removed <code>Props only</code> mode.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Intercepts <code>fetch</code> and <code>XMLHttpRequest</code> except <code>OPTIONS</code> and extension-originated calls.</li><li>Summary columns: status, method, name, duration, size.</li><li>Detailed view: params, auth, headers, request, response — only CORS-exposed headers where applicable.</li><li>Pause/resume capture; recording on by default on first open.</li><li><code>Breakpoint</code> — pause and edit outbound requests before send.</li><li><code>Mock Response</code> — intercept and return a synthetic response.</li><li>Quick copy of URLs, tokens, and key fields.</li><li>Clear all captured requests.</li><li>Event-driven architecture without polling for lower CPU.</li><li>Binary detection — textual preview suppressed with metadata only.</li></ul><h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="core-2" tabindex="-1">Core <a class="header-anchor" href="#core-2" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><p><code>Display Mode</code> — move the app into a <code>DevTools</code> tab or disable pure overlay.</p></li><li><p><code>Options</code> reorganized into logical sections.</p></li><li><p><code>Props</code>, <code>Pinia Store</code>, and <code>Network</code> filters editable inline without jumping to Options.</p></li><li><p>Fixed JSON text-mode click target area.</p></li><li><p>Large JSON no longer truncates — heavy CSS disabled for performance.</p></li><li><p>Update notifications revised:</p><ul><li><code>Dismiss</code> → <code>Later</code>;</li><li><code>Download</code> → <code>Preview</code> pointing to <code>Options → About</code>;</li><li>detail block with <code>Ignore</code> and <code>Download</code>.</li></ul></li></ul><hr><h3 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Fixed missing Props hover highlight in <code>Standalone</code>.</li></ul><hr><h3 id="network-1" tabindex="-1">Network <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><code>form-data</code> support for reading and traffic substitution.</li><li>Saved files for reuse with <code>Breakpoint</code> / <code>form-data</code>.</li><li><code>Rewrite Breakpoint</code> / <code>Rewrite Mock</code> — overwrite existing rules instead of duplicating.</li><li>Badges for active <code>Breakpoint</code> / <code>Mock</code> per request; click opens matching Options.</li><li>Search by HTTP status code.</li><li><code>Breakpoint</code> rules consider HTTP method.</li><li>Fixed inspector not opening when a <code>breakpoint</code> fired.</li><li>Context menu entries: <code>Disable/Enable Breakpoint</code>, <code>Disable/Enable Mock</code>, <code>Delete Breakpoint/Mock</code> (shown when applicable).</li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><h4 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h4><ul><li>Core settings (<code>Display Mode</code>, <code>Search Parameters</code>, <code>Auto Refresh</code>, <code>JSON Editor Mode</code>) grouped together.</li><li><code>Settings Management</code> moved from the tab header.</li></ul><h4 id="network-2" tabindex="-1">Network <a class="header-anchor" href="#network-2" aria-label="Permalink to &quot;Network&quot;">​</a></h4><ul><li><code>Search Settings</code> split into their own section and decoupled.</li><li><code>Breakpoints</code> / <code>Mocks</code> table layout fixes — rows no longer over-stretch.</li><li>Toggle and edit existing rules.</li></ul><h4 id="props-2" tabindex="-1">Props <a class="header-anchor" href="#props-2" aria-label="Permalink to &quot;Props&quot;">​</a></h4><ul><li>Settings file controls moved into the section.</li><li><code>Component Blacklist</code> moved here from the general block.</li><li><code>Favorite Components</code> moved here from the general block.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store&quot;">​</a></h4><ul><li>Settings file controls moved into the section.</li></ul><h4 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h4><ul><li><p><code>Release notes</code> and <code>Check for updates</code> (extension only).</p></li><li><p>When an update exists:</p><ul><li><code>Ignore</code> silences this version until a newer one ships;</li><li><code>Download</code> fetches the app archive.</li></ul></li></ul><h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network-3" tabindex="-1">Network <a class="header-anchor" href="#network-3" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><code>Postman</code> collection export from captured <code>Network</code> traffic.</li><li>Single-panel mode: <code>Copy cURL</code> replaced with a header context menu — <code>Breakpoint</code>, <code>Mock</code>, <code>Copy cURL</code>.</li><li>Right-click context menu on request detail header.</li></ul><hr><h3 id="props-3" tabindex="-1">Props <a class="header-anchor" href="#props-3" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Favorites and blacklist behavior fixes.</li><li>Blacklist applied during collection traversal (not only table filtering) — faster Props load.</li><li>Quick actions menu for <code>Props</code>.</li><li>Refresh open component in read mode.</li><li>Shortcut jump to favorites from the favorites counter.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Pinia <code>favorites</code> with shortcut navigation.</li><li>Quick actions menu for <code>Pinia Store</code>.</li><li>Refresh open entry in read mode.</li><li><code>Options</code> supports manual favorite entries with <code>wildcards</code>.</li></ul><hr><h3 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>User files now persist as local copies in app storage.</li><li><code>Standalone</code> uses dedicated local storage — settings survive relaunch and work across sites.</li><li>Tree JSON editor temporarily disabled — text mode only.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p><code>Options → General → Customize</code> adds theming:</p><ul><li><code>Dark / Light</code> color scheme;</li><li><code>Image</code> background (<code>File / Link</code>) with stills, <code>GIF</code>, <code>MP4</code>;</li><li><code>Browse</code> or pick from saved files;</li><li>Add by URL;</li><li><code>Image Opacity</code>, <code>Blur</code>, <code>Noise Intensity / Opacity</code>, <code>Position (X / Y)</code>, <code>Scale</code> (<code>100–200%</code>).</li></ul><hr><h3 id="ui-ux-1" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-1" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Responsive layout for smaller screens.</li><li>Wide layout: split list + details.</li><li>~<code>1000px</code> width collapses to single-panel.</li><li><code>Esc</code> closes panels/dialogs.</li><li><code>Ctrl+F</code> search in <code>DevTools</code> tab mode.</li><li>Loading skeletons for <code>Props</code> / <code>Pinia</code> tables instead of raw “Not found”.</li><li>Column visibility toggles for <code>Props</code>, <code>Pinia</code>, <code>Network</code>.</li><li>Chevron redesign for iframe open/close.</li><li>Table context menus (right-click).</li></ul><hr><h3 id="performance-1" tabindex="-1">Performance <a class="header-anchor" href="#performance-1" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Blacklist applied during Props tree pre-walk — faster data collection and tab load.</li></ul><hr><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>JSON edit hit area while scrolling.</li><li><code>Network</code> tab freezes after long sessions.</li><li><code>Ctrl+A</code> selects only the focused input.</li><li>Reset/delete buttons respect <code>disabled</code> state.</li><li><code>Options</code> tables with many rows.</li><li>JSON edit mode styling.</li><li>Minor cosmetic fixes.</li></ul><h2 id="_2-4-0-2026-04-19" tabindex="-1">[2.4.0] - 2026-04-19 <a class="header-anchor" href="#_2-4-0-2026-04-19" aria-label="Permalink to &quot;[2.4.0] - 2026-04-19&quot;">​</a></h2><h3 id="network-4" tabindex="-1">Network <a class="header-anchor" href="#network-4" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>When <code>Pause</code> is enabled, inspector interceptors are detached, so native DevTools display the <code>original initiator</code> instead of <code>injected.ts</code>.</li><li>The <code>Network</code> table now uses virtualization for better performance and reduced UI freezes.</li><li>The request details view now opens on the <code>Response</code> tab by default.</li><li>When a <code>Breakpoint</code> is triggered, the paused method automatically opens on the <code>Request</code> tab.</li><li><code>Search by</code> lists on the <code>Network</code> tab and in <code>Options</code> now support searching by the <code>Name</code> column.</li></ul><hr><h3 id="props-4" tabindex="-1">Props <a class="header-anchor" href="#props-4" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p><code>Props</code> performance has been significantly improved, making <code>auto refresh</code> safe to use.</p></li><li><p>In the <code>Props</code> table, the <code>Props</code> column has been split into <code>Passed</code> and <code>Declared</code> (all columns can be hidden):</p><ul><li><code>Passed</code> — number of props currently received;</li><li><code>Declared</code> — number of props declared on the component.</li></ul></li><li><p>In the right-side <code>Props details</code> panel, data is now split into two tabs:</p><ul><li><code>Passed</code> — props currently received (opened by default);</li><li><code>Declared</code> — all props declared by the component.</li></ul></li><li><p>The <code>Props details</code> panel now includes a <code>Size</code> parameter.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (Props Inspector) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (Props Inspector)&quot;">​</a></h4><ul><li>Added page element selection mode similar to <code>Chrome DevTools Elements</code>.</li><li>Allows selecting elements directly on the page for quick <code>Props</code> filtering.</li><li>Highlights <code>Vue</code> components on hover.</li><li>Displays quick element info: <code>Name</code>, <code>Root element</code>, <code>Received Props</code>, <code>Nested components</code>.</li><li>After selection, <code>Props</code> displays only the selected element and its nested components.</li><li>The filter can be quickly cleared via the <code>Filtered</code> badge.</li></ul><hr><h3 id="ui-ux-2" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-2" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="windowed-mode" tabindex="-1">Windowed mode <a class="header-anchor" href="#windowed-mode" aria-label="Permalink to &quot;Windowed mode&quot;">​</a></h4><ul><li>Added support for windowed mode with saved position for both launch modes.</li><li>Updated the iframe open chevron with a drag indicator.</li><li>Added support for docking the launcher to any of the four browser edges with automatic vertical stretching.</li></ul><h4 id="auto-launch-settings" tabindex="-1">Auto launch settings <a class="header-anchor" href="#auto-launch-settings" aria-label="Permalink to &quot;Auto launch settings&quot;">​</a></h4><ul><li><p>Added <code>Whitelist</code> for automatic app launch and <code>Blacklist</code> for excluded sites where launch and launcher display are disabled.</p></li><li><p>Added extension <code>popup</code> with quick actions:</p><ul><li><code>Forced Launch</code> — launches the app ignoring whitelist, blacklist, and static-site restrictions;</li><li><code>Reset Settings</code> — resets all extension settings.</li></ul></li></ul><h4 id="other-ui-improvements" tabindex="-1">Other UI improvements <a class="header-anchor" href="#other-ui-improvements" aria-label="Permalink to &quot;Other UI improvements&quot;">​</a></h4><ul><li>Fixed <code>JSON</code> styling for large data volumes.</li><li>Added exact search when entering values in quotes; without quotes, search works in <code>like</code> mode.</li><li>Minor visual interface improvements.</li><li>Improved <code>Esc</code> behavior in <code>DevTools</code> mode: first closes nested tabs, and when nothing else remains, opens the <code>DevTools Console</code>.</li></ul><hr><h3 id="performance-2" tabindex="-1">Performance <a class="header-anchor" href="#performance-2" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Improved <code>Props</code> and <code>Store</code> detection mechanism for significantly faster data retrieval.</li><li>Increased limits for maximum readable <code>Props</code> count.</li><li>Refactored internal project structure: removed unused modules, dead code, and duplicated logic.</li></ul><hr><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Full project documentation has been added.</li><li>Added a <code>Documentation</code> section to the landing page.</li><li>Added quick documentation access via <code>Options → About</code>.</li></ul><hr><h3 id="fixes-1" tabindex="-1">Fixes <a class="header-anchor" href="#fixes-1" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>Blocked native right-click menu inside the application context menu. • Fixed incorrect favorite detection in Props details when names matched.</li><li>Improved search behavior in <code>DevTools mode</code>: fixed cases where search could stop working and added highlight reset when clearing the field or closing search.</li><li>Pinia store <strong>Getters</strong> save no longer wipes reactive state with bulk <code>delete</code> (incorrect for <code>ref</code>/nested objects); updates merge like Pinia’s <code>$patch</code>, with clearer errors when a key fails.</li></ul>',89)])])}const m=o(t,[["render",r]]);export{p as __pageData,m as default};
